#!/usr/bin/env python3
"""
Primer paso del bot de WhatsApp:
  - src/lib/whatsapp.ts: helper para enviar mensajes via Cloud API.
  - src/app/api/whatsapp/webhook/route.ts: verificacion de Meta (GET) y
    recepcion de mensajes (POST), con una respuesta de eco temporal
    mientras se integra la IA de agendamiento.
  - src/components/SettingsClient.tsx: nueva seccion 'WhatsApp' para
    guardar el Phone Number ID y el Access Token por negocio, y ver
    la URL del webhook a configurar en Meta.

Requiere haber corrido antes 002_whatsapp.sql en Supabase.

Ejecutar desde la raiz del repo (carpeta que contiene 'src'):
    python3 apply_whatsapp_webhook.py
"""

import base64
from pathlib import Path

FILES = {
    'src/lib/whatsapp.ts': """""",
    'src/app/api/whatsapp/webhook/route.ts': """""",
    'src/components/SettingsClient.tsx': """""",
}

def main():
    for relpath, b64 in FILES.items():
        p = Path(relpath)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))
        print(f"escrito: {relpath} ({p.stat().st_size} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'Webhook de WhatsApp (verificacion + eco) y configuracion en Settings'")
    print("  git push")

if __name__ == "__main__":
    main()